sn_aia_tool.script:
(function(inputs) {
    var identifier = inputs.number;
    var decision = inputs.agent_decision;
    var recommendation = inputs.agent_recommendation;
    var kbCited = inputs.kb_article_cited || '';
    var timestamp = inputs.api_call_timestamp || '';

    // Validate decision
    var validDecisions = ['approve', 'deny', 'escalate'];
    if (validDecisions.indexOf(decision.toLowerCase()) === -1) {
        return JSON.stringify({ status: 'error', message: 'Invalid agent_decision: ' + decision + '. Must be approve, deny, or escalate.' });
    }
    decision = decision.toLowerCase();

    // Find the claim - try by number first, then by sys_id
    var gr = new GlideRecord('x_snc_medwc_auto_0_warranty_claim');
    var found = false;

    if (identifier.indexOf('WC') === 0) {
        gr.addQuery('number', identifier);
        gr.query();
        found = gr.next();
    }

    if (!found && identifier.length === 32) {
        gr = new GlideRecord('x_snc_medwc_auto_0_warranty_claim');
        found = gr.get(identifier);
    }

    if (!found) {
        gr = new GlideRecord('x_snc_medwc_auto_0_warranty_claim');
        found = gr.get(identifier);
    }

    if (!found) {
        return JSON.stringify({ status: 'error', message: 'No warranty claim found with: ' + identifier });
    }

    var sysId = gr.getValue('sys_id');
    var claimNumber = gr.getValue('number');

    // Set decision fields
    gr.setValue('agent_decision', decision);
    gr.setValue('agent_recommendation', recommendation.substring(0, 4000));
    if (kbCited) gr.setValue('kb_article_cited', kbCited);

    // Set timestamp
    if (timestamp) {
        var gdt = new GlideDateTime();
        gdt.setDisplayValue(timestamp);
        gr.setValue('api_call_timestamp', gdt.getValue());
    } else {
        gr.setValue('api_call_timestamp', new GlideDateTime().getValue());
    }

    // Add audit work note
    var now = new GlideDateTime();
    var workNote = 'AI Agent Decision: ' + decision.toUpperCase() + '\n\n';
    workNote += 'Recommendation:\n' + recommendation.substring(0, 2000) + '\n\n';
    if (kbCited) workNote += 'Policy Reference: ' + kbCited + '\n\n';
    workNote += 'Decision timestamp: ' + now.getDisplayValue();
    gr.work_notes = workNote;

    // Update with workflow enabled (triggers Business Rule)
    gr.setWorkflow(true);
    gr.autoSysFields(true);
    gr.update();

    // Verify persistence
    var verify = new GlideRecord('x_snc_medwc_auto_0_warranty_claim');
    verify.get(sysId);

    return JSON.stringify({
        status: 'success',
        message: 'Claim ' + claimNumber + ' finalized as ' + decision.toUpperCase(),
        claim_sys_id: sysId,
        claim_number: verify.getValue('number'),
        agent_decision: verify.getValue('agent_decision'),
        state: verify.getValue('state'),
        kb_article_cited: verify.getValue('kb_article_cited')
    });
})(inputs);
